patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..355b1ffed54e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5255,7 +5255,92 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
       return new ICmpInst(ICmpInst::getSignedPredicate(Pred),
                           Constant::getNullValue(Op0->getType()), Op0);
   }
-
+  // icmp pred (sdiv X, C), X where C > 1 --> icmp newPred X, 0
+  // icmp pred X, (sdiv X, C) where C > 1 --> icmp newPred 0, X
+  // Similar for udiv.
+  const APInt *DivC;
+  if (match(Op0, m_SDiv(m_Specific(Op1), m_APInt(DivC))) && DivC->sgt(1)) {
+    ICmpInst::Predicate NewPred = Pred;
+    bool Handled = true;
+    switch (Pred) {
+    case ICmpInst::ICMP_SLT: NewPred = ICmpInst::ICMP_SGT; break;
+    case ICmpInst::ICMP_SLE: NewPred = ICmpInst::ICMP_SGE; break;
+    case ICmpInst::ICMP_SGT: NewPred = ICmpInst::ICMP_SLT; break;
+    case ICmpInst::ICMP_SGE: NewPred = ICmpInst::ICMP_SLE; break;
+    case ICmpInst::ICMP_EQ:  // fallthrough
+    case ICmpInst::ICMP_NE:  // keep predicate
+      break;
+    default:
+      Handled = false;
+      break;
+    }
+    if (Handled)
+      return new ICmpInst(NewPred, Op1, Constant::getNullValue(Op1->getType()));
+  }
+  if (match(Op1, m_SDiv(m_Specific(Op0), m_APInt(DivC))) && DivC->sgt(1)) {
+    // Swap predicate and apply same mapping as above.
+    ICmpInst::Predicate SwappedPred = ICmpInst::getSwappedPredicate(Pred);
+    ICmpInst::Predicate NewPred = SwappedPred;
+    bool Handled = true;
+    switch (SwappedPred) {
+    case ICmpInst::ICMP_SLT: NewPred = ICmpInst::ICMP_SGT; break;
+    case ICmpInst::ICMP_SLE: NewPred = ICmpInst::ICMP_SGE; break;
+    case ICmpInst::ICMP_SGT: NewPred = ICmpInst::ICMP_SLT; break;
+    case ICmpInst::ICMP_SGE: NewPred = ICmpInst::ICMP_SLE; break;
+    case ICmpInst::ICMP_EQ:  // fallthrough
+    case ICmpInst::ICMP_NE:  // keep predicate
+      break;
+    default:
+      Handled = false;
+      break;
+    }
+    if (Handled)
+      return new ICmpInst(NewPred, Op0, Constant::getNullValue(Op0->getType()));
+  }
+  // udiv
+  if (match(Op0, m_UDiv(m_Specific(Op1), m_APInt(DivC))) && DivC->ugt(1)) {
+    ICmpInst::Predicate NewPred = Pred;
+    bool Handled = true;
+    switch (Pred) {
+    case ICmpInst::ICMP_ULT: NewPred = ICmpInst::ICMP_NE; break;
+    case ICmpInst::ICMP_ULE:
+      return replaceInstUsesWith(I, Constant::getAllOnesValue(I.getType()));
+    case ICmpInst::ICMP_UGT:
+      return replaceInstUsesWith(I, Constant::getNullValue(I.getType()));
+    case ICmpInst::ICMP_UGE:
+      return replaceInstUsesWith(I, Constant::getAllOnesValue(I.getType()));
+    case ICmpInst::ICMP_EQ:  // fallthrough
+    case ICmpInst::ICMP_NE:  // keep predicate
+      break;
+    default:
+      Handled = false;
+      break;
+    }
+    if (Handled)
+      return new ICmpInst(NewPred, Op1, Constant::getNullValue(Op1->getType()));
+  }
+  if (match(Op1, m_UDiv(m_Specific(Op0), m_APInt(DivC))) && DivC->ugt(1)) {
+    ICmpInst::Predicate SwappedPred = ICmpInst::getSwappedPredicate(Pred);
+    ICmpInst::Predicate NewPred = SwappedPred;
+    bool Handled = true;
+    switch (SwappedPred) {
+    case ICmpInst::ICMP_ULT: NewPred = ICmpInst::ICMP_NE; break;
+    case ICmpInst::ICMP_ULE:
+      return replaceInstUsesWith(I, Constant::getAllOnesValue(I.getType()));
+    case ICmpInst::ICMP_UGT:
+      return replaceInstUsesWith(I, Constant::getNullValue(I.getType()));
+    case ICmpInst::ICMP_UGE:
+      return replaceInstUsesWith(I, Constant::getAllOnesValue(I.getType()));
+    case ICmpInst::ICMP_EQ:  // fallthrough
+    case ICmpInst::ICMP_NE:  // keep predicate
+      break;
+    default:
+      Handled = false;
+      break;
+    }
+    if (Handled)
+      return new ICmpInst(NewPred, Op0, Constant::getNullValue(Op0->getType()));
+  }
   if (Value *V = foldMultiplicationOverflowCheck(I))
     return replaceInstUsesWith(I, V);

